function _runHealthCheck(){var branches=['flock','app','missions','extra'];branches.forEach(function(b){var pill=document.getElementById('health-pill-'+b);var provPill=document.getElementById('prov-health-'+b);if(pill){pill.className='health-pill health-pill-unknown';pill.innerHTML='<span class="health-dot"></span> Checking\u2026';}
if(provPill){provPill.className='health-pill health-pill-unknown';provPill.innerHTML='<span class="health-dot"></span> \u2026';}});if(typeof TheVine==='undefined'||!TheVine.manifest||!TheVine.manifest.diagnostics){branches.forEach(function(b){var pill=document.getElementById('health-pill-'+b);if(pill){pill.className='health-pill health-pill-fail';pill.innerHTML='<span class="health-dot"></span> No API client';}});return;}
TheVine.manifest.diagnostics().then(function(diag){var branchList=diag.branches||[];branchList.forEach(function(r){var alias=r.alias;var pill=document.getElementById('health-pill-'+alias);var provPill=document.getElementById('prov-health-'+alias);var cls,txt;if(r.status==='online'){var ms=r.latencyMs||0;if(ms<2000){cls='health-pill-ok';txt=ms+'ms';}
else{cls='health-pill-warn';txt=ms+'ms (slow)';}}else{cls='health-pill-fail';txt='Offline';}
if(pill){pill.className='health-pill '+cls;pill.innerHTML='<span class="health-dot"></span> '+txt;}
if(provPill){provPill.className='health-pill '+cls;provPill.innerHTML='<span class="health-dot"></span> '+txt;}});var ts=document.getElementById('health-timestamp');if(ts)ts.textContent='Last check: '+new Date().toLocaleTimeString();}).catch(function(err){branches.forEach(function(b){var pill=document.getElementById('health-pill-'+b);if(pill){pill.className='health-pill health-pill-fail';pill.innerHTML='<span class="health-dot"></span> Error';}});});}
