async function _permToggle(email,moduleKey,el){var current=el.textContent.trim();var next;if(current==='\u2014')next='grant';else if(current==='GRANT')next='deny';else next='clear';try{el.textContent='\u2026';await TheVine.flock.call('permissions.set',{targetEmail:email,module:moduleKey,access:next});if(next==='grant'){el.textContent='GRANT';el.style.color='var(--success)';el.style.fontWeight='700';}else if(next==='deny'){el.textContent='DENY';el.style.color='var(--danger)';el.style.fontWeight='700';}else{el.textContent='\u2014';el.style.color='var(--ink-muted)';el.style.fontWeight='';}
var effTd=el.closest('td').nextElementSibling;if(effTd){if(next==='grant')effTd.innerHTML='<span style="color:var(--success);">\u2713</span>';else if(next==='deny')effTd.innerHTML='<span style="color:var(--danger);">\u2717</span>';else{var defTd=el.closest('td').previousElementSibling;var hasCheck=defTd&&defTd.textContent.indexOf('\u2713')>=0;effTd.innerHTML=hasCheck?'<span style="color:var(--success);">\u2713</span>':'<span style="color:var(--danger);">\u2717</span>';}}}catch(e){el.textContent=current;alert('Failed: '+(e.message||'Unknown error'));}}
